import { describe, test, expect } from "bun:test";
import { composePolicy } from "../composer";
import type { Layer } from "../../schema/policy.schema";

describe("Composer", () => {
  test("FSD derives state as feature-based automatically", () => {
    const policy = composePolicy({
      pattern: "feature-sliced",
      output_mode: "compact",
      naming_strategy: "PascalCase",
    });

    expect(policy.stack.state_philosophy).toBe("feature-based");
    expect(policy.state_constraints.global_state_scope).toBe("feature-based");
  });

  test("flat derives state as flexible automatically", () => {
    const policy = composePolicy({
      pattern: "flat",
      output_mode: "compact",
      naming_strategy: "kebab-case",
    });

    expect(policy.stack.state_philosophy).toBe("flexible");
    expect(policy.state_constraints.global_state_scope).toBe("any");
  });

  test("modular derives state as module-based automatically", () => {
    const policy = composePolicy({
      pattern: "modular",
      output_mode: "compact",
      naming_strategy: "PascalCase",
    });

    expect(policy.stack.state_philosophy).toBe("module-based");
    expect(policy.state_constraints.global_state_scope).toBe("module-based");
  });

  test("atomic derives state as minimal automatically", () => {
    const policy = composePolicy({
      pattern: "atomic",
      output_mode: "compact",
      naming_strategy: "kebab-case",
    });

    expect(policy.stack.state_philosophy).toBe("minimal");
    expect(policy.state_constraints.global_state_scope).toBe("minimal");
  });

  test("utility-first styling removes style companions", () => {
    const policy = composePolicy({
      pattern: "feature-sliced",
      output_mode: "compact",
      naming_strategy: "kebab-case",
      styling_strategy: "utility-first",
    });

    const component = policy.file_conventions.types.component!;
    expect(component.companions?.style).toBeUndefined();
    expect(policy.ui_constraints.style_co_location).toBe(false);
    expect(policy.ui_constraints.allowed_style_extensions).toHaveLength(0);
  });

  test("scoped styling adds companion .module.css required", () => {
    const policy = composePolicy({
      pattern: "feature-sliced",
      output_mode: "compact",
      naming_strategy: "kebab-case",
      styling_strategy: "scoped",
    });

    const component = policy.file_conventions.types.component!;
    expect(component.companions?.style?.required).toBe(true);
    expect(component.companions?.style?.extensions).toContain(".module.css");
    expect(policy.ui_constraints.style_co_location).toBe(true);
  });

  test("css-in-js removes companion but keeps co_location true", () => {
    const policy = composePolicy({
      pattern: "modular",
      output_mode: "compact",
      naming_strategy: "PascalCase",
      styling_strategy: "css-in-js",
    });

    const component = policy.file_conventions.types.component!;
    expect(component.companions?.style).toBeUndefined();
    expect(policy.ui_constraints.style_co_location).toBe(true);
    expect(policy.ui_constraints.allowed_style_extensions).toHaveLength(0);
  });

  test("atomic + utility-first has no style companions", () => {
    const policy = composePolicy({
      pattern: "atomic",
      output_mode: "compact",
      naming_strategy: "kebab-case",
      styling_strategy: "utility-first",
    });

    for (const typeDef of Object.values(policy.file_conventions.types)) {
      expect(typeDef.companions?.style).toBeUndefined();
    }
  });

  test("FSD with PascalCase naming applies correct file patterns", () => {
    const policy = composePolicy({
      pattern: "feature-sliced",
      output_mode: "compact",
      naming_strategy: "PascalCase",
    });

    expect(policy.file_conventions.types.component?.pattern).toBe(
      "*Component.tsx",
    );
    expect(policy.file_conventions.types.hook?.pattern).toBe("*Hook.ts");

    const featuresLayer = policy.layers.find((l: Layer) => l.id === "features");
    expect(featuresLayer?.responsibilities).toBeDefined();
    expect(featuresLayer?.responsibilities?.owns[0]).toContain(
      "user interactions with business value",
    );

    expect(policy.fsd_config?.segments).toContain("ui");
  });

  test("flat pattern disables barrel exports regardless of template default", () => {
    const policy = composePolicy({
      pattern: "flat",
      output_mode: "compact",
      naming_strategy: "kebab-case",
    });
    expect(policy.structural_constraints.barrel_exports_required).toBe(false);
  });

  test("modular template has correct import_matrix (no self-import)", () => {
    const policy = composePolicy({
      pattern: "modular",
      output_mode: "compact",
      naming_strategy: "PascalCase",
    });

    const modulesImports = policy.import_matrix["modules"];
    expect(modulesImports).not.toContain("modules");
    expect(modulesImports).toContain("shared");
  });

  test("composePolicy preserves responsibilities through validation", () => {
    const policy = composePolicy({
      pattern: "feature-sliced",
      output_mode: "compact",
      naming_strategy: "kebab-case",
    });

    const appLayer = policy.layers.find((l: Layer) => l.id === "app");
    expect(appLayer?.responsibilities).toBeDefined();
    expect(appLayer?.responsibilities?.owns).toContain("providers");
  });

  test("flat template has meaningful forbidden_patterns", () => {
    const policy = composePolicy({
      pattern: "flat",
      output_mode: "compact",
      naming_strategy: "kebab-case",
    });

    expect(policy.state_constraints.forbidden_patterns.length).toBeGreaterThan(
      0,
    );
    expect(policy.file_conventions.forbidden_patterns.length).toBeGreaterThan(
      0,
    );
  });

  test("throws on unknown pattern", () => {
    expect(() =>
      composePolicy({
        pattern: "non-existent",
        output_mode: "compact",
        naming_strategy: "kebab-case",
      }),
    ).toThrow("Template not found: non-existent");
  });

  test("camelCase naming strategy produces valid patterns", () => {
    const policy = composePolicy({
      pattern: 'flat',
      output_mode: 'compact',
      naming_strategy: 'camelCase',
    });
    expect(policy.naming_conventions.global_strategy).toBe('camelCase');
    expect(policy.file_conventions.types.component?.pattern).toBe('*.component.tsx');
    expect(policy.file_conventions.types.hook?.pattern).toBe('*.hook.ts');
  });
});



import * as v from 'valibot';
import { PolicySchema, type Policy } from '../../schema/policy.schema';
import { TemplateRegistry } from '../registry';
import { resolveNamingPatterns, VALID_STRATEGIES } from './naming';
import { STATE_BY_PATTERN } from '../shared/pattern-state';

export interface UserSelections {
  pattern: string;
  output_mode: 'compact';
  naming_strategy: typeof VALID_STRATEGIES[number];
  styling_strategy?: string;
}

const VALID_STYLING = ['utility-first', 'scoped', 'css-in-js', 'any'] as const;

const STYLING_EXTENSIONS: Record = {
  'scoped':       ['.module.css', '.css'],
  'css-in-js':    [],
  'utility-first': [],
};

function deepClone(obj: T): T {
  return JSON.parse(JSON.stringify(obj));
}

function isObject(item: any): item is Record {
  return item && typeof item === 'object' && !Array.isArray(item);
}

/**
 * Deep merges two objects. Arrays are replaced entirely by source (no concat).
 * Scalar overrides and nested object merges work recursively.
 */
function deepMerge(target: any, source: any): any {
  if (!isObject(target) || !isObject(source)) return source;
  const output = { ...target };
  for (const key of Object.keys(source)) {
    if (Array.isArray(source[key])) {
      output[key] = source[key]; // arrays: source always wins
    } else if (isObject(source[key]) && isObject(target[key])) {
      output[key] = deepMerge(target[key], source[key]);
    } else {
      output[key] = source[key];
    }
  }
  return output;
}

export const composePolicy = (selections: UserSelections): Policy => {
  // Validate styling_strategy
  if (selections.styling_strategy && !VALID_STYLING.includes(selections.styling_strategy as any)) {
    throw new Error(`Invalid styling_strategy: "${selections.styling_strategy}". Valid: ${VALID_STYLING.join(', ')}`);
  }

  // 1. Get base template (clone to avoid mutation)
  const template = deepClone(TemplateRegistry.getTemplate(selections.pattern));

  // 2. Derivar state da arch — não do input do usuário
  const state = STATE_BY_PATTERN[selections.pattern] ?? {
    philosophy: 'flexible',
    scope: 'any',
  };

  // 3. Define overrides
  const overrides: any = {
    meta: {
      output_mode: 'compact' as 'compact',
      generated_at: new Date().toISOString()
    },
    stack: {
      pattern: selections.pattern,
      state_philosophy: state.philosophy,
      styling_strategy: selections.styling_strategy || 'any',
    },
    state_constraints: {
      global_state_scope: state.scope,
      derived_state_strategy: selections.pattern === 'flat' ? 'any' : 'selectors',
    },
    naming_conventions: {
      global_strategy: selections.naming_strategy
    }
  };

  // 4. Merge base with overrides
  let merged = deepMerge(template, overrides);

  // 5. Update naming patterns based on strategy
  merged.file_conventions.types = resolveNamingPatterns(
    merged.file_conventions.types,
    selections.naming_strategy
  );

  // 6. Pattern-specific overrides
  if (selections.pattern === 'flat') {
    merged.structural_constraints.barrel_exports_required = false;
  }

  // 7. Styling-specific companion + extension overrides
  const styleExts = STYLING_EXTENSIONS[selections.styling_strategy ?? ''];

  for (const typeDef of Object.values(merged.file_conventions.types) as any[]) {
    if (!typeDef.companions?.style) continue;

    if (!styleExts || styleExts.length === 0) {
      delete typeDef.companions.style;
    } else {
      typeDef.companions.style.required = true;
      typeDef.companions.style.extensions = styleExts;
    }
  }

  // 8. Update ui_constraints based on styling strategy
  if (selections.styling_strategy === 'css-in-js') {
    merged.ui_constraints.style_co_location = true;
    merged.ui_constraints.allowed_style_extensions = [];
  }

  if (selections.styling_strategy === 'scoped') {
    merged.ui_constraints.style_co_location = true;
    merged.ui_constraints.allowed_style_extensions = ['.module.css', '.css'];
  }

  if (selections.styling_strategy === 'utility-first') {
    merged.ui_constraints.style_co_location = false;
    merged.ui_constraints.allowed_style_extensions = [];
  }

  // 9. Validate the final object
  return v.parse(PolicySchema, merged);
};



import type { Policy } from '../../schema/policy.schema';

const FILE_SUFFIXES: Record<string, Record> = {
  'kebab-case': {
    component: '*.component.tsx',
    hook:      '*.hook.ts',
    store:     '*.store.ts',
    service:   '*.service.ts',
    types:     '*.types.ts',
    constants: '*.constants.ts',
  },
  'PascalCase': {
    component: '*Component.tsx',
    hook:      '*Hook.ts',
    store:     '*Store.ts',
    service:   '*Service.ts',
    types:     '*Types.ts',
    constants: '*Constants.ts',
  },
  'snake_case': {
    component: '*_component.tsx',
    hook:      '*_hook.ts',
    store:     '*_store.ts',
    service:   '*_service.ts',
    types:     '*_types.ts',
    constants: '*_constants.ts',
  },
  'camelCase': {
    component: '*.component.tsx',
    hook:      '*.hook.ts',
    store:     '*.store.ts',
    service:   '*.service.ts',
    types:     '*.types.ts',
    constants: '*.constants.ts',
  },
};

export const VALID_STRATEGIES = ['kebab-case', 'PascalCase', 'snake_case', 'camelCase'] as const;
export type NamingStrategy = typeof VALID_STRATEGIES[number];

export const resolveNamingPatterns = (
  types: Policy['file_conventions']['types'],
  strategy: string
): Policy['file_conventions']['types'] => {
  const suffixes = FILE_SUFFIXES[strategy];
  if (!suffixes) {
    throw new Error(`Unknown naming strategy: "${strategy}". Valid: ${VALID_STRATEGIES.join(', ')}`);
  }

  const result = JSON.parse(JSON.stringify(types));

  for (const key of Object.keys(result)) {
    if (suffixes[key]) {
      result[key].pattern = suffixes[key];
    }
  }

  return result;
};



