import type { Policy } from '../../schema/policy.schema';
import { featureSlicedTemplate } from './templates/feature-sliced';
import { flatTemplate } from './templates/flat';
import { modularTemplate } from './templates/modular';
import { atomicTemplate } from './templates/atomic';
import { loadTemplateFromFile } from './loader';

let TEMPLATES: Record = {
  'feature-sliced': featureSlicedTemplate,
  'flat': flatTemplate,
  'modular': modularTemplate,
  'atomic': atomicTemplate,
};

export const TemplateRegistry = {
  getTemplate: (id: string): Policy => {
    const template = TEMPLATES[id];
    if (!template) {
      throw new Error(`Template not found: ${id}`);
    }
    return template;
  },
  listTemplates: (): string[] => {
    return Object.keys(TEMPLATES);
  },
  registerTemplate: (id: string, template: Policy): void => {
    if (TEMPLATES[id]) {
      throw new Error(`Template "${id}" is already registered. Use a unique id.`);
    }
    TEMPLATES[id] = template;
  },

  loadFromFile: (filePath: string): void => {
    const { id, template } = loadTemplateFromFile(filePath);
    TemplateRegistry.registerTemplate(id, template);
  },

  reset: (): void => {
    // Resets to built-in templates only. Useful for tests.
    TEMPLATES = {
      'feature-sliced': featureSlicedTemplate,
      'flat': flatTemplate,
      'modular': modularTemplate,
      'atomic': atomicTemplate,
    };
  },
};



import { describe, test, expect, beforeEach } from 'bun:test';
import { TemplateRegistry } from './index';

describe('TemplateRegistry external templates', () => {
  beforeEach(() => {
    TemplateRegistry.reset();
  });

  test('listTemplates returns built-in templates', () => {
    const list = TemplateRegistry.listTemplates();
    expect(list).toContain('feature-sliced');
    expect(list).toContain('flat');
    expect(list).toContain('modular');
    expect(list).toContain('atomic');
  });

  test('registerTemplate adds a new template', () => {
    const base = TemplateRegistry.getTemplate('flat');
    TemplateRegistry.registerTemplate('my-custom', { ...base, meta: { ...base.meta, version: '2.0.0' } });
    expect(TemplateRegistry.listTemplates()).toContain('my-custom');
  });

  test('registerTemplate throws on duplicate id', () => {
    const base = TemplateRegistry.getTemplate('flat');
    expect(() => TemplateRegistry.registerTemplate('flat', base)).toThrow('already registered');
  });

  test('reset removes custom templates and restores built-ins', () => {
    const base = TemplateRegistry.getTemplate('flat');
    TemplateRegistry.registerTemplate('temp-template', base);
    TemplateRegistry.reset();
    expect(TemplateRegistry.listTemplates()).not.toContain('temp-template');
    expect(TemplateRegistry.listTemplates()).toContain('flat');
  });

  test('loadFromFile throws if file does not exist', () => {
    expect(() => TemplateRegistry.loadFromFile('/nonexistent/path/template.json'))
      .toThrow('not found');
  });

  test('loadFromFile registers a valid template from disk', () => {
    const { tmpdir } = require('os');
    const { writeFileSync } = require('fs');
    const path = require('path');

    const base = TemplateRegistry.getTemplate('flat');
    const id = `my-team-${Date.now()}`;
    const tmpPath = path.join(tmpdir(), `${id}.json`);
    writeFileSync(tmpPath, JSON.stringify({ ...base, meta: { ...base.meta, version: '9.0.0' } }));

    TemplateRegistry.loadFromFile(tmpPath);
    expect(TemplateRegistry.listTemplates()).toContain(id);
    expect(TemplateRegistry.getTemplate(id).meta.version).toBe('9.0.0');
  });
});



import fs from 'fs-extra';
import path from 'path';
import * as v from 'valibot';
import { PolicySchema, type Policy } from '../../schema/policy.schema';

/**
 * Loads a custom Policy template from a JSON file.
 * Validates the file against PolicySchema before registering.
 * Throws a descriptive error if the file is missing, invalid JSON, or fails schema validation.
 */
export const loadTemplateFromFile = (filePath: string): { id: string; template: Policy } => {
  const absolutePath = path.resolve(filePath);

  if (!fs.existsSync(absolutePath)) {
    throw new Error(`Custom template file not found: ${absolutePath}`);
  }

  let raw: unknown;
  try {
    raw = fs.readJsonSync(absolutePath);
  } catch {
    throw new Error(`Failed to parse JSON from template file: ${absolutePath}`);
  }

  // Derive the template id from the filename without extension
  const id = path.basename(absolutePath, path.extname(absolutePath));

  let template: Policy;
  try {
    template = v.parse(PolicySchema, raw);
  } catch (err) {
    throw new Error(`Template "${id}" failed schema validation: ${err instanceof Error ? err.message : String(err)}`);
  }

  return { id, template };
};



