import type { Policy } from '../../schema/policy.schema';

const renderLayerTable = (policy: Policy): string => {
  const { layers, import_matrix, side_effect_boundaries } = policy;

  let table = '| Layer | May Import | Responsibilities | Side Effects |\n';
  table += '|-------|------------|------------------|--------------|\n';

  layers.forEach(layer => {
    const mayImport = import_matrix[layer.id]?.join(', ') || '—';
    const isAllowed = side_effect_boundaries.allowed_in_layers.includes(layer.id);
    const sideEffect = isAllowed ? '✓ allowed' : '✗ forbidden';
    const res = layer.responsibilities ? `**Owns:** ${layer.responsibilities.owns.join(', ')}
**Not:** ${layer.responsibilities.must_not.join(', ')}` : '—';
    table += `| ${layer.id} | ${mayImport} | ${res} | ${sideEffect} |\n`;
  });

  return table;
};

const renderNamingTable = (policy: Policy): string => {
  const { file_conventions, naming_conventions } = policy;

  let table = '| Type | File Pattern | Export Name Convention |\n';
  table += '|------|--------------|------------------------|\n';

  const keyMap: Record = {
    types: 'type',
    constants: 'constant',
    store: 'store',
    service: 'service',
    hook: 'hook',
    component: 'component',
  };

  const getNamingConvention = (typeName: string): string => {
    if (typeName === 'types')     return 'PascalCase (*Type | *Props suffix)';
    if (typeName === 'constants') return 'SCREAMING_SNAKE_CASE';
    if (typeName === 'utils')     return 'camelCase';

    const namingKey = keyMap[typeName] || typeName;
    return naming_conventions[namingKey] || '—';
  };

  Object.entries(file_conventions.types).forEach(([typeName, def]) => {
    const symbolConv = getNamingConvention(typeName);
    table += `| ${typeName} | \`${def.pattern}\` | \`${symbolConv}\` |\n`;
  });

  return table;
};

const renderCompanionsTable = (policy: Policy): string => {
  const { file_conventions } = policy;

  let table = '| File Type | Required | Optional |\n';
  table += '|-----------|----------|----------|\n';

  Object.entries(file_conventions.types).forEach(([typeName, def]) => {
    if (!def.companions || Object.keys(def.companions).length === 0) {
      table += `| ${typeName} | — | — |\n`;
      return;
    }

    const companionEntries = Object.entries(def.companions);

    const required = companionEntries
      .filter(([_, rule]) => rule.required)
      .map(([_, rule]) => `\`*${rule.extensions[0]}\``)
      .join(' + ') || '—';

    const optional = companionEntries
      .filter(([_, rule]) => !rule.required)
      .map(([_, rule]) => `\`*${rule.extensions[0]}\``)
      .join(', ') || '—';

    table += `| ${typeName} | ${required} | ${optional} |\n`;
  });

  return table;
};

const renderBoundariesTable = (policy: Policy): string => {
  const { abstraction_boundaries } = policy;
  if (!abstraction_boundaries?.length) return '';

  let table = '\n### Abstraction Boundaries\n\n';
  table += '| Boundary | Inner | Outer | Interface Required | Forbidden Leakage |\n';
  table += '|----------|-------|-------|--------------------|-------------------|\n';

  abstraction_boundaries.forEach(b => {
    table += `| ${b.boundary_name} | ${b.inner_layer} | ${b.outer_layer} | ${b.interface_required ? `✓ (${b.interface_location})` : '✗'} | ${b.forbidden_leakage.join(', ')} |\n`;
  });

  return table;
};

const getSegmentRules = (segment: string, layerId: string, policy: Policy): string => {
  const { ui_constraints, side_effect_boundaries } = policy;

  if (layerId === 'pages' && segment === 'ui') {
    return 'route components only — compose widgets, no business logic';
  }
  if (layerId === 'entities' && segment === 'api') {
    return 'data access for this entity — maps to domain types, no raw responses';
  }
  if (layerId === 'features' && segment === 'api') {
    return 'feature-specific mutations — calls entity api, never raw fetch';
  }
  if (layerId === 'entities' && segment === 'model') {
    return 'entity state, selectors, types — pure business logic';
  }
  if (layerId === 'features' && segment === 'model') {
    return 'feature state, selectors — only for this feature';
  }

  const rules: Record = {
    ui:     `components — max ${ui_constraints.component_max_lines} lines, ${ui_constraints.logic_in_components ? 'logic allowed' : 'no logic — extract to model'}`,
    model:  `store, selectors, types — no side effects`,
    api:    `data fetching — ${side_effect_boundaries.async_pattern}, map errors to domain types`,
    lib:    `pure utils — stateless, no imports from ui or model`,
    config: `constants, feature flags`,
  };

  return rules[segment] ?? '';
};

const renderFSDStructure = (policy: Policy): string => {
  const { layers, import_matrix, ui_constraints, structural_constraints, file_conventions } = policy;
  const { fsd_config } = policy;

  const lines: string[] = ['src/'];

  for (const layer of layers) {
    const allowed = import_matrix[layer.id] ?? [];
    const res = layer.responsibilities;

    lines.push(`├── ${layer.id}/`);
    lines.push(`│   # imports: [${allowed.join(', ') || 'none'}]`);

    if (res?.must_not?.length) {
      lines.push(`│   # must not: ${res.must_not[0]}`);
    }

    if (!['app', 'shared'].includes(layer.id)) {
      lines.push(`│   ├── /          # business domain unit`);

      const segments = fsd_config?.segments ?? ['ui', 'model', 'api', 'lib'];
      for (const seg of segments) {
        const segRules = getSegmentRules(seg, layer.id, policy);
        lines.push(`│   │   ├── ${seg}/`);
        if (segRules) lines.push(`│   │   │   # ${segRules}`);
      }

      if (structural_constraints.barrel_exports_required) {
        lines.push(`│   │   └── index.ts      # public api — only export what consumers need`);
      }
    }

    if (layer.id === 'shared') {
      lines.push(`│   ├── ui-kit/           # design system primitives`);
      lines.push(`│   ├── api/              # base http client, interceptors`);
      lines.push(`│   ├── lib/              # pure utils — no business logic`);
      lines.push(`│   └── types/            # global types only`);
    }
  }

  return lines.join('\n');
};

const renderModularStructure = (policy: Policy): string => {
  const { ui_constraints, structural_constraints, file_conventions } = policy;

  return [
    'src/',
    '├── modules/',
    '│   ├── /        # one per business capability',
    `│   │   ├── components/       # max ${ui_constraints.component_max_lines} lines each`,
    `│   │   │   └── ComponentName.tsx`,
    `│   │   │       # ${ui_constraints.logic_in_components ? 'logic allowed here' : 'no logic — use hooks/'}`,
    '│   │   ├── hooks/            # all logic lives here',
    '│   │   ├── services/         # external I/O only — API, storage',
    '│   │   ├── types/            # module-scoped types',
    structural_constraints.barrel_exports_required
      ? '│   │   └── index.ts          # public api — never import internals directly'
      : '│   │   └── (no barrel required)',
    '│   │   # cross-module imports: FORBIDDEN — use shared/',
    '├── shared/',
    '│   ├── ui/                   # design system, generic components',
    '│   ├── utils/                # pure functions — min 2 consumers to justify',
    '│   └── types/                # global contracts only',
  ].join('\n');
};

const renderFlatStructure = (policy: Policy): string => {
  return [
    'src/',
    '├── components/               # all components live here',
    '│   └── ComponentName.tsx     # logic colocated — ok at this scale',
    '├── hooks/                    # extract when logic repeats 2+ times',
    '├── services/                 # extract when touching external I/O',
    '├── types/                    # shared types',
    '└── utils/                    # pure functions',
    '',
    '# graduation signals — consider migrating pattern when:',
    '#   > 20 components in /components',
    '#   same data fetched in 3+ places',
    '#   2+ devs regularly conflicting on same files',
  ].join('\n');
};

const renderAtomicStructure = (policy: Policy): string => {
  const { layers, stack } = policy;
  const totalLayers = layers.length;
  const hasStyleFile = !['utility-first', 'css-in-js'].includes(stack.styling_strategy ?? '');

  const layerLines = layers.flatMap((layer, i) => {
    const isLast = i === totalLayers - 1;
    const prefix = isLast ? '└──' : '├──';
    const childPrefix = isLast ? '    ' : '│   ';

    let lines = [`${prefix} ${layer.id}/`];

    if (layer.id === 'pages') {
      lines.push(`${childPrefix}├── /`);
      lines.push(`${childPrefix}│   └── PageName.tsx`);
    } else if (!['shared'].includes(layer.id)) {
      lines.push(`${childPrefix}├── /`);
      lines.push(`${childPrefix}│   ├── ComponentName.tsx`);
      if (hasStyleFile) {
        lines.push(`${childPrefix}│   └── ComponentName.module.css`);
      }
    } else {
      lines.push(`${childPrefix}├── utils/`);
      lines.push(`${childPrefix}├── types/`);
      lines.push(`${childPrefix}└── theme/`);
    }

    return lines;
  });

  return ['src/', ...layerLines].join('\n');
};

const renderExpectedStructure = (policy: Policy): string => {
  const { stack } = policy;
  const pattern = stack.pattern;

  const renderers: Record string> = {
    'feature-sliced': () => renderFSDStructure(policy),
    'modular':        () => renderModularStructure(policy),
    'flat':           () => renderFlatStructure(policy),
    'atomic':         () => renderAtomicStructure(policy),
  };

  const renderer = renderers[pattern];
  if (!renderer) return '';

  return `## Expected Directory Structure\n\n\`\`\`\n${renderer()}\n\`\`\``;
};

export const renderMarkdown = (policy: Policy): string => {
  const { stack, meta, structural_constraints, ui_constraints, state_constraints, file_conventions, side_effect_boundaries, domain_rules, naming_conventions } = policy;

  return `# Architecture Policy
> Pattern: **${stack.pattern}** | State: **${stack.state_philosophy}** | Styling: **${stack.styling_strategy}**

---

## Layer Rules
Imports are unidirectional. Each layer may only import from layers listed below it.
Violations of import rules are **not permitted**.

${renderLayerTable(policy)}

${renderBoundariesTable(policy)}

**Cross-feature imports:** ${structural_constraints.cross_feature_imports.replace(/-/g, ' ')}
**Circular imports:** ${structural_constraints.circular_imports}

---

${renderExpectedStructure(policy)}

---

${domain_rules ? `## Domain Rules
- **Entities location:** \`${domain_rules.entities_location}\`
- **Value objects:** ${domain_rules.value_objects_allowed ? 'allowed' : 'forbidden'}
- **Immutable entities:** ${domain_rules.entity_rules.must_be_immutable ? 'YES' : 'no'}
- **Framework-agnostic domain:** ${domain_rules.entity_rules.no_framework_imports ? 'YES (no React/Axios/etc in entities)' : 'no'}
- **Validation:** ${domain_rules.entity_rules.validation_location}
- **Anemic model:** ${domain_rules.anemic_model_allowed ? 'allowed' : 'FORBIDDEN — business logic belongs in entities'}
- **Ubiquitous Language:** ${domain_rules.ubiquitous_language.enforced ? 'enforced' : 'optional'}

---\n\n` : ''}## File Conventions

### Naming
> Files: \`${naming_conventions.global_strategy}\` globally · Symbols: per-type rules below

${renderNamingTable(policy)}

### Required Companions

${renderCompanionsTable(policy)}

### Structure Rules
- **Co-location:** ${file_conventions.colocation} — companions must live beside source file
- **Test placement:** ${file_conventions.test_placement}
- **Public API:** ${file_conventions.public_api.required ? `every feature root requires \`${file_conventions.public_api.filename || 'index'}.ts\` — internal files must not be imported directly` : 'optional'}
- **Max directory depth:** ${file_conventions.directory?.max_depth || 'N/A'}
- **Barrel exports:** ${structural_constraints.barrel_exports_required ? 'required at feature roots only' : 'optional'}

### Forbidden Patterns
${file_conventions.forbidden_patterns.map(p => `- \`${p}\``).join('\n')}

---

## Component Composition Rules
- **Max lines:** ${ui_constraints.component_max_lines}
- **Max props:** ${ui_constraints.component_max_props} — split into compound component if exceeded
- **No prop drilling beyond depth ${ui_constraints.prop_drilling_max_depth}** — lift to store or context
- **Logic in components:** ${ui_constraints.logic_in_components ? 'allowed' : 'FORBIDDEN — extract to hooks'}
- **Presentational components** must not import from \`state\` or \`services\` layers
- **Prefer composition over configuration:** ${ui_constraints.prefer_composition ? 'YES — pass children/slots, avoid boolean prop explosion' : 'optional'}

---

## Abstraction Rules
- Extract to **hook** when: logic repeats across 2+ components OR exceeds 20 lines inside component
- Extract to **service** when: logic touches external I/O (API, storage, cookies)
- Extract to **utility** when: logic is pure, stateless, domain-agnostic
- **Do not abstract preemptively** — wrong abstraction costs more than duplication

---

## State & Async Rules
- **Scope:** ${state_constraints.global_state_scope}
- **Derived state:** ${state_constraints.derived_state_strategy}
- **Data fetching:** ${side_effect_boundaries.data_fetching_scope}, consumed via hooks
- **All promises must be handled** — no floating async calls
- **API errors must not reach UI raw** — map to domain error types in service layer
- **Every async UI operation requires** loading state + error state

---

## Type Rules
- **No \`any\`** — use \`unknown\` + type narrowing
- **Props interface required** per component — no inline type literals
- **No type assertions (\`as\`)** except at data boundaries (API responses, DOM events)

---

*Generated by agent-arch · [edit templates to change rules]*
`.trim();
};



import type { Policy } from '../../schema/policy.schema';

// Helper to flatten the new file_conventions structure
const flattenFileConventions = (fc: Policy['file_conventions']) => {
  const lines: string[] = [];
  for (const [typeName, def] of Object.entries(fc.types)) {
    const companions = def.companions
      ? Object.entries(def.companions)
          .map(([name, rule]) => `${name}(${rule.required ? 'required' : 'optional'})`)
          .join(', ')
      : 'none';
    lines.push(`${typeName}=${def.pattern} companions=[${companions}]`);
  }
  return lines;
};

// ─── Compact: máxima densidade, zero redundância ──────────────────────────────
const renderCompact = (policy: Policy): string => {
  const { stack, meta, layers, import_matrix, structural_constraints,
          ui_constraints, state_constraints, file_conventions,
          naming_conventions, side_effect_boundaries } = policy;

  const layerLines = layers
    .map(l => `${l.id.toUpperCase()}→[${(import_matrix[l.id] ?? []).join(',')}]`)
    .join(' | ');

  const namingLines = flattenFileConventions(file_conventions).join(' | ');

  return [
    `ARCH_POLICY v${meta.version} | ${stack.domain} | ${stack.pattern}`,
    `STACK state=${stack.state_philosophy} style=${stack.styling_strategy} routing=${stack.routing_strategy}`,
    `LAYERS ${layerLines}`,
    `STRUCTURE ${renderCompactStructure(policy)}`,
    `RULES circular=FORBIDDEN cross_feature=${structural_constraints.cross_feature_imports} max_depth=${structural_constraints.max_component_depth} barrel=${structural_constraints.barrel_exports_required ? 'REQUIRED' : 'OPTIONAL'}`,
    `UI max_lines=${ui_constraints.component_max_lines} max_props=${ui_constraints.component_max_props} prop_drilling=${ui_constraints.prop_drilling_max_depth} logic=${ui_constraints.logic_in_components ? 'ALLOWED' : 'FORBIDDEN'} style_coloc=${ui_constraints.style_co_location ? 'REQUIRED' : 'OPTIONAL'} preferred_extensions=${ui_constraints.allowed_style_extensions.join(',') || 'none'}`,
    `STATE scope=${state_constraints.global_state_scope} local=${state_constraints.local_state_allowed ? 'ALLOWED' : 'FORBIDDEN'} derived=${state_constraints.derived_state_strategy}`,
    `STATE_FORBIDDEN ${state_constraints.forbidden_patterns.join(',')}`,
    `SIDE_EFFECTS allowed=[${side_effect_boundaries.allowed_in_layers.join(',')}] forbidden=[${side_effect_boundaries.forbidden_in_layers.join(',')}] fetch=${side_effect_boundaries.data_fetching_scope}`,
    `NAMING ${Object.entries(naming_conventions).map(([k, v]) => `${k}=${v}`).join(' ')}`,
    `FILES ${namingLines}`,
    `COLOC=${file_conventions.colocation.toUpperCase()} TEST=${file_conventions.test_placement} PUBLIC_API=${file_conventions.public_api.required ? 'REQUIRED(index.ts)' : 'OPTIONAL'}`,
    file_conventions.forbidden_patterns.length
      ? `FILE_FORBIDDEN ${file_conventions.forbidden_patterns.join(',')}`
      : null,
  ].filter(Boolean).join('\n');
};

const renderCompactStructure = (policy: Policy): string => {
  const { stack, layers, fsd_config } = policy;
  const pattern = stack.pattern;

  if (pattern === 'feature-sliced') {
    const segments = fsd_config?.segments ?? ['ui', 'model', 'api', 'lib'];
    const layerDirs = layers.map(l => l.id).join(', ');
    return `FSD: src/{${layerDirs}}//{${segments.join(',')}}`;
  }

  if (pattern === 'modular') {
    const internals = Object.keys(policy.file_conventions.types)
      .filter(t => !['types', 'constants'].includes(t))
      .join(',');
    return `MODULAR: src/{modules//{${internals}},shared/{ui,utils,types}}`;
  }

  if (pattern === 'flat') {
    return `FLAT: src/{components,hooks,services,types,utils} - graduation signals: >20 components, duplicate fetch in 3+ places`;
  }

  if (pattern === 'atomic') {
    const layerDirs = layers.map(l => l.id).join(' → ');
    return `ATOMIC: src/{${layerDirs}}`;
  }

  return '';
};

// ─── Public API ───────────────────────────────────────────────────────────────
export interface RenderResult {
  content: string;
  tokens: number;
}

export const renderPrompt = (policy: Policy): RenderResult => {
  const rendered = renderCompact(policy);
  const tokens = Math.ceil(rendered.length / 4);
  return { content: rendered, tokens };
};



import { describe, test, expect } from 'bun:test';
import { composePolicy } from '../composer';
import { renderMarkdown } from './markdown-renderer';
import { renderPrompt } from './prompt-renderer';

describe('Markdown Renderer', () => {
  test('FSD + utility-first compact output matches snapshot', () => {
    const policy = composePolicy({
      pattern: 'feature-sliced',
      output_mode: 'compact',
      naming_strategy: 'kebab-case',
      styling_strategy: 'utility-first',
    });
    expect(renderMarkdown(policy)).toMatchSnapshot();
  });

  test('Modular + utility-first compact output matches snapshot', () => {
    const policy = composePolicy({
      pattern: 'modular',
      output_mode: 'compact',
      naming_strategy: 'PascalCase',
      styling_strategy: 'utility-first',
    });
    expect(renderMarkdown(policy)).toMatchSnapshot();
  });

  test('Flat compact output matches snapshot', () => {
    const policy = composePolicy({
      pattern: 'flat',
      output_mode: 'compact',
      naming_strategy: 'kebab-case',
    });
    expect(renderMarkdown(policy)).toMatchSnapshot();
  });

  test('Atomic + utility-first — no css files in structure or companions', () => {
    const policy = composePolicy({
      pattern: 'atomic',
      output_mode: 'compact',
      naming_strategy: 'kebab-case',
      styling_strategy: 'utility-first',
    });
    const output = renderMarkdown(policy);
    expect(output).toMatchSnapshot();
    expect(output).not.toContain('.module.css');
  });

  test('Atomic + scoped — css files appear in structure and companions', () => {
    const policy = composePolicy({
      pattern: 'atomic',
      output_mode: 'compact',
      naming_strategy: 'kebab-case',
      styling_strategy: 'scoped',
    });
    const output = renderMarkdown(policy);
    expect(output).toContain('.module.css');
  });

  test('FSD + scoped — style companion required', () => {
    const policy = composePolicy({
      pattern: 'feature-sliced',
      output_mode: 'compact',
      naming_strategy: 'kebab-case',
      styling_strategy: 'scoped',
    });
    const output = renderMarkdown(policy);
    expect(output).toContain('.module.css');
  });
});

describe('Prompt Renderer', () => {
  test('FSD compact output renders without errors', () => {
    const policy = composePolicy({
      pattern: 'feature-sliced',
      output_mode: 'compact',
      naming_strategy: 'kebab-case'
    });
    const { content, tokens } = renderPrompt(policy);
    expect(content.length).toBeGreaterThan(0);
    expect(tokens).toBeGreaterThan(0);
  });

  test('FSD output contains key sections', () => {
    const policy = composePolicy({
      pattern: 'feature-sliced',
      output_mode: 'compact',
      naming_strategy: 'kebab-case'
    });
    const { content } = renderPrompt(policy);
    expect(content).toContain('feature-sliced');
    expect(content).toContain('LAYERS');
    expect(content).toContain('STRUCTURE');
  });
});



export const STATE_BY_PATTERN: Record = {
  'feature-sliced': { philosophy: 'feature-based', scope: 'feature-based' },
  'modular':        { philosophy: 'module-based',  scope: 'module-based'  },
  'flat':           { philosophy: 'flexible',      scope: 'any'           },
  'atomic':         { philosophy: 'minimal',       scope: 'minimal'       },
};



import fs from 'fs-extra';
import path from 'path';
import type { Policy } from '../../schema/policy.schema';
import { renderMarkdown } from '../renderer/markdown-renderer';
import { renderPrompt } from '../renderer/prompt-renderer';

export const writePolicyFiles = async (policy: Policy, targetDir: string = '.ai') => {
  await fs.ensureDir(targetDir);

  const policyMdPath = path.join(targetDir, 'policy.md');
  const promptTxtPath = path.join(targetDir, 'system.prompt.txt');
  const policyJsonPath = path.join(targetDir, 'policy.json');

  // Separate renders are intentional for modularity, although policy is immutable here.
  const { content: promptContent, tokens } = renderPrompt(policy);

  const policyWithTokens: Policy = {
    ...policy,
    token_metadata: {
      ...policy.token_metadata,
      estimated_prompt_tokens: tokens,
    }
  };

  await fs.writeJson(policyJsonPath, policyWithTokens, { spaces: 2 });
  await fs.writeFile(promptTxtPath, promptContent);

  const mdContent = renderMarkdown(policyWithTokens); // Use the policy with tokens
  await fs.writeFile(policyMdPath, mdContent);

  return {
    policyMdPath,
    promptTxtPath,
    policyJsonPath,
    mdContent,
    promptContent,
  };
};



import * as v from 'valibot';

export const OutputModeSchema = v.literal('compact');

export const LayerResponsibilitiesSchema = v.object({
  owns: v.array(v.string()),
  must_not: v.array(v.string()),
  depends_on_abstractions: v.boolean(),
});

export const LayerSchema = v.object({
  id: v.string(),
  allowed_imports: v.array(v.string()),
  forbidden_imports: v.optional(v.array(v.string())),
  responsibilities: v.optional(LayerResponsibilitiesSchema),
});

// ─── File Conventions agora com companion opcional e pattern livre ────────────
export const CompanionRuleSchema = v.object({
  required: v.boolean(),
  extensions: v.array(v.string()), // ex: ['.test.ts', '.spec.ts']
});

export const FileTypeConventionSchema = v.object({
  pattern: v.string(),             // ex: "*.component.tsx"
  companions: v.optional(          // undefined = sem companions obrigatórios
    v.record(v.string(), CompanionRuleSchema)
  ),
  // ex: { test: { required: true, extensions: ['.test.ts'] },
  //        style: { required: false, extensions: ['.module.css'] } }
});

export const FileConventionsSchema = v.object({
  // Cada tipo de arquivo tem sua própria definição completa
  types: v.record(v.string(), FileTypeConventionSchema),
  // ex: { component: { pattern: "*.component.tsx", companions: { test: {...}, style: {...} } } }

  colocation: v.union([v.literal('strict'), v.literal('loose'), v.literal('none')]),

  public_api: v.object({
    required: v.boolean(),
    filename: v.optional(v.string()),       // default: "index"
    extensions: v.optional(v.array(v.string())), // default: [".ts", ".tsx"]
    expose_internals: v.boolean(),
  }),

  test_placement: v.union([
    v.literal('colocated'),
    v.literal('__tests__-sibling'),
    v.literal('dedicated-root'),
  ]),

  directory: v.optional(v.object({
    max_depth: v.number(),
    feature_root_marker: v.optional(v.string()), // ex: "index.ts"
  })),

  forbidden_patterns: v.array(v.string()),
});

export const SideEffectBoundariesSchema = v.object({
  allowed_in_layers: v.array(v.string()),
  forbidden_in_layers: v.array(v.string()),
  async_pattern: v.string(),
  data_fetching_scope: v.string(),
});

export const UIConstraintsSchema = v.object({
  component_max_lines: v.number(),
  component_max_props: v.number(),
  prop_drilling_max_depth: v.number(),
  logic_in_components: v.boolean(),
  style_co_location: v.boolean(),
  allowed_style_extensions: v.array(v.string()),
  prefer_composition: v.boolean(),
});

export const AbstractionBoundarySchema = v.object({
  boundary_name: v.string(),
  inner_layer: v.string(),
  outer_layer: v.string(),
  interface_required: v.boolean(),
  interface_location: v.string(),
  forbidden_leakage: v.array(v.string()),
});

export const ErrorHandlingSchema = v.object({
  layer: v.string(),
  strategy: v.union([
    v.literal('throw-domain-error'),
    v.literal('return-result-type'),
    v.literal('propagate'),
    v.literal('silent-log'),
  ]),
  allowed_error_types: v.array(v.string()),
  forbidden_error_types: v.array(v.string()),
  boundary_mapping_required: v.boolean(),
});

export const DomainRulesSchema = v.object({
  entities_location: v.string(),
  value_objects_allowed: v.boolean(),
  entity_rules: v.object({
    must_be_immutable: v.boolean(),
    no_framework_imports: v.boolean(),
    validation_location: v.union([
      v.literal('constructor'),
      v.literal('factory-function'),
      v.literal('external-validator'),
    ]),
  }),
  anemic_model_allowed: v.boolean(),
  ubiquitous_language: v.object({
    enforced: v.boolean(),
    glossary_path: v.optional(v.string()),
  }),
});

export const PolicySchema = v.object({
  meta: v.object({
    version: v.string(),
    generated_at: v.string(),
    output_mode: OutputModeSchema,
    token_budget: v.optional(v.number()),
  }),
  stack: v.object({
    domain: v.literal('frontend'),
    pattern: v.string(),
    state_philosophy: v.string(),
    styling_strategy: v.string(),
    routing_strategy: v.string(),
  }),
  fsd_config: v.optional(v.object({
    segments: v.array(v.string()),
  })),
  layers: v.array(LayerSchema),
  import_matrix: v.record(v.string(), v.array(v.string())),
  abstraction_boundaries: v.optional(v.array(AbstractionBoundarySchema)),
  error_handling_strategy: v.optional(v.array(ErrorHandlingSchema)),
  domain_rules: v.optional(DomainRulesSchema),
  structural_constraints: v.object({
    max_component_depth: v.number(),
    barrel_exports_required: v.boolean(),
    circular_imports: v.literal('FORBIDDEN'),
    cross_feature_imports: v.union([
      v.literal('via-public-api-only'),
      v.literal('FORBIDDEN'),
      v.literal('allowed'),
    ]),
  }),
  ui_constraints: UIConstraintsSchema,
  state_constraints: v.object({
    global_state_scope: v.string(),
    local_state_allowed: v.boolean(),
    derived_state_strategy: v.string(),
    forbidden_patterns: v.array(v.string()),
  }),
  side_effect_boundaries: SideEffectBoundariesSchema,
  naming_conventions: v.looseObject({
    global_strategy: v.union([
      v.literal('kebab-case'),
      v.literal('PascalCase'),
      v.literal('snake_case'),
      v.literal('camelCase'),
    ]),
    component: v.optional(v.string()),
    hook: v.optional(v.string()),
    store: v.optional(v.string()),
    service: v.optional(v.string()),
    constant: v.optional(v.string()),
    type: v.optional(v.string()),
    test: v.optional(v.string()),
  }),
  file_conventions: FileConventionsSchema,
  token_metadata: v.object({
    estimated_prompt_tokens: v.number(),
    compression_applied: v.boolean(),
    omitted_sections: v.array(v.string()),
  }),
});
export type Policy = v.InferOutput;
export type Layer = v.InferOutput;
export type FileConventions = v.InferOutput;
export type FileTypeConvention = v.InferOutput;
export type CompanionRule = v.InferOutput;
export type OutputMode = v.InferOutput;



import React, { useState } from 'react';
