const STEP_LABELS: Record = {
  welcome: 'Start',
  pattern: 'Pattern',
  styling: 'Styling',
  naming: 'Naming',
  confirm: 'Confirm',
  generating: 'Generating...',
  done: 'Done',
};

const GUIDED_STEPS: Step[] = ['pattern', 'styling', 'naming', 'confirm'];

// ─── Sub-components ────────────────────────────────────────────────────────────

const Header = ({ stepIndex, totalSteps }: { stepIndex: number; totalSteps: number }) => (


      AGENT-ARCH 
      — AI Agent Architecture Policy Generator

    {totalSteps > 1 && (

        {GUIDED_STEPS.map((s, i) => (

            <Text color={i < stepIndex ? 'green' : i === stepIndex ? 'cyan' : 'gray'}>
              {i < stepIndex ? '●' : i === stepIndex ? '◉' : '○'}

             {STEP_LABELS[s]}
            {i < GUIDED_STEPS.length - 1 &&  › }

        ))}

    )}

);

const OptionDescription = ({ option }: { option: OptionWithMeta | undefined }) => {
  if (!option) return null;
  return (

      {option.description}

        💡 {option.hint}

      {option.impact && (

          {option.impact}

      )}

  );
};

const QuestionStep = ({
  stepKey,
  onSelect,
}: {
  stepKey: string;
  onSelect: (value: string) => void;
}) => {
  const options = OPTIONS[stepKey] ?? [];
  const [focused, setFocused] = useState(options[0]?.value ?? '');

  const inkItems = options.map((o) => ({ label: o.label, value: o.value }));
  const focusedOption = options.find((o) => o.value === focused);

  return (


        {stepKey === 'welcome' ? 'How do you want to start?' : `Select ${STEP_LABELS[stepKey as Step]}`}

      Use ↑↓ to navigate, Enter to select

         onSelect(item.value)}
          onHighlight={(item) => setFocused(item.value)}
        />



  );
};

const ConfirmScreen = ({
  selections,
  onConfirm,
  onBack,
}: {
  selections: Partial;
  onConfirm: () => void;
  onBack: () => void;
}) => {
  useInput((input, key) => {
    if (key.return) onConfirm();
    if (key.escape || input === 'b') onBack();
  });

  const derivedState = STATE_BY_PATTERN[selections.pattern ?? '']?.philosophy ?? 'flexible';

  return (

      Review & Confirm
      Verify your choices before generating the policy.


        Selected Configuration

          {(['pattern', 'styling_strategy', 'naming_strategy'] as const).map((key) => {
             const labelMap: Record = {
               pattern: 'Pattern',
               styling_strategy: 'Styling',
               naming_strategy: 'Naming',
             };
             return (


                  {labelMap[key]}:

                {(selections as any)[key]}

             );
          })}


              State:

            {derivedState}
             ← derived from pattern





        ↵ Enter 
        to generate  
        Esc / b 
        to go back


  );
};

// ─── Main App ──────────────────────────────────────────────────────────────────

const RECOMMENDED_DEFAULTS: UserSelections = {
  pattern: 'feature-sliced',
  styling_strategy: 'utility-first',
  naming_strategy: 'kebab-case',
  output_mode: 'compact',
};

export const App = () => {
  const { exit } = useApp();
  const [step, setStep] = useState('welcome');
  const [selections, setSelections] = useState<Partial>({});
  const [isExpressMode, setIsExpressMode] = useState(false);
  const [error, setError] = useState(null);
  const [generatedPrompt, setGeneratedPrompt] = useState('');

  const stepIndex = GUIDED_STEPS.indexOf(step);

  const handleWelcomeSelect = (value: string) => {
    if (value === 'express') {
      setIsExpressMode(true);
      setSelections(RECOMMENDED_DEFAULTS);
      setStep('confirm');
    } else {
      setIsExpressMode(false);
      setStep('pattern');
    }
  };

  const handleSelect = (stepKey: Step, value: string) => {
    let mapping: Partial = {};
    if (stepKey === 'styling') mapping = { styling_strategy: value };
    else if (stepKey === 'naming') mapping = { naming_strategy: value as UserSelections['naming_strategy'] };
    else mapping = { [stepKey]: value } as any;

    const next: Partial = { ...selections, ...mapping, output_mode: 'compact' };
    setSelections(next);

    const idx = GUIDED_STEPS.indexOf(stepKey);
    const nextStep = GUIDED_STEPS[idx + 1];
    if (nextStep) setStep(nextStep);
  };

  const handleConfirm = async () => {
    setStep('generating');
    try {
      const policy = composePolicy(selections as UserSelections);
      const { mdContent } = await writePolicyFiles(policy);

      setGeneratedPrompt(mdContent);

      setStep('done');
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err));
      setStep('confirm');
    }
  };

  useInput((input, key) => {
    if (step === 'done') {
      if (input === 'q' || key.escape || key.return) exit();
    }
  });

  return (




        {/* Welcome */}
        {step === 'welcome' && }

        {/* Wizard steps */}
        {(['pattern', 'styling', 'naming'] as const).map(
          (s) =>
            step === s && (
               handleSelect(s, val)} />
            ),
        )}

        {/* Confirm */}
        {step === 'confirm' && (
           setStep(isExpressMode ? 'welcome' : 'naming')}
          />
        )}

        {/* Generating */}
        {step === 'generating' && (

            ⟳ Generating policy artifacts...

              • Rendering policy.md
              • Rendering system.prompt.txt


        )}

        {/* Done */}
        {step === 'done' && (


              ✓ Architecture policy generated successfully!

                Artifacts created in .ai/ folder.




              Preview: .ai/policy.md

                {/* Use the markdown preview instead */}

                  {generatedPrompt
                    .split('\n')
                    .slice(0, 12)
                    .map(line => line.replace(/^#+\s/, '').replace(/\*\*/g, ''))
                    .join('\n')}

                ... (truncated)




              Press 
              Enter / q
               to exit


        )}

        {/* Error */}
        {error && (

            ✗ Error: {error}

        )}


  );
};



#!/usr/bin/env bun
import { Command } from 'commander';
import React from 'react';
import { render } from 'ink';
import { App } from './ui/app';

const program = new Command();

program
  .name('agent-arch')
  .description('Opinionated architecture governance for AI agents')
  .version('1.0.0');

program
  .command('init')
  .description('Initialize architecture policy for the project')
  .option('-t, --template ', 'Path to a custom JSON template file')
  .action(async (options) => {
    if (options.template) {
      // Load the custom template before launching the UI
      const { TemplateRegistry } = await import('./core/registry');
      TemplateRegistry.loadFromFile(options.template);
      console.log(`Custom template loaded from: ${options.template}`);
    }
    render(React.createElement(App));
  });

program.parse(process.argv);
